args.sparql:
SELECT DISTINCT ?opponent ?country WHERE {
  ?match wdt:P31 wd:Q8049739 ;  # Doubles match
         wdt:P2269 wd:Q7550143 ;  # Final stage
         wdt:P1397 wd:Q6793601 ;  # Mauricio Echazú as participant
         wdt:P1685 ?tournament ;
         wdt:P585 ?date ;
         wdt:P732 ?opponent .
  ?tournament wdt:P31 wd:Q1027342 .  # ITF Future tournament
  FILTER (MONTH(?date) = 9) .
  ?opponent wdt:P599 ?country .
}

